CREATE TABLE `tbl_access_id` (
  `ACCESSNO` int(11) NOT NULL AUTO_INCREMENT,
  `TENANT_ID` mediumint(5) NOT NULL DEFAULT '0',
  `CN` varchar(80) NOT NULL,
  PRIMARY KEY (`ACCESSNO`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8;


CREATE TABLE `james_mail_deleted_id` (
  `MAILBOX_ID` bigint(20) NOT NULL,
  `MAIL_UID` bigint(20) NOT NULL,
  PRIMARY KEY (`MAILBOX_ID`,`MAIL_UID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

sqlMap.select:
SELECT COUNT(member_id) FROM tbl_permissiongroupinfo WHERE group_id = #groupId# AND company_id = #companyId# AND tenant_id = #tenantId# AND ( (member_type = 'USER' AND member_id = #userId#) OR (member_type = 'DEPT' AND sub_dept_yn = 'N' AND (member_id = #deptId# or member_id IN (SELECT deptid FROM tbl_addjobmaster WHERE cn = #userId# and tenant_id = #tenantId#))) OR (member_type = 'JIKWI' AND member_id IN ( SELECT extensionattribute7 FROM tbl_usermaster WHERE cn = #userId# AND tenant_id = #tenantId# AND PHYSICALDELIVERYOFFICENAME = #companyId# UNION DISTINCT SELECT jobid FROM tbl_addjobmaster WHERE cn = #userId# AND tenant_id = #tenantId# ) ) OR (member_type = 'JIKCHEK' AND member_id = (SELECT extensionattribute8 FROM tbl_usermaster WHERE cn = #userId# AND tenant_id = #tenantId# AND PHYSICALDELIVERYOFFICENAME = #companyId#))
OR (member_type = 'DEPT' AND sub_dept_yn = 'Y' AND (member_id = #deptId# or member_id IN (SELECT deptid FROM tbl_addjobmaster WHERE cn = #userId# and tenant_id = #tenantId#))
)

