	`ATTACHLIMITCNT`  bigint(10) DEFAULT NULL,
	`TENANT_ID` mediumint(5) NOT NULL,
	`COMPANYID` varchar(80) NOT NULL,
	PRIMARY KEY (`TENANT_ID`,`COMPANYID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
